INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(4 AS Decimal(5, 0)), N'Sala de despiece de carnes.', N'Establecer las condiciones y requisitos específicos que deben cumplir las salas de despiece de carnes dedicadas a la obtención y comercialización de porciones más peque¦as que las canales, las medias canales y las medias canales despiezadas en un máximo de tres piezas o los cuartos, al deshuese de las mismas, su envasado o no y a la comercialización de despojos (enteros envasados o no) o fileteados. Todas ellas procedentes de animales domésticos de las especies bovina, porcina, ovina, caprina y los solípedos domésticos.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(5 AS Decimal(5, 0)), N'Almacén frigorífico de carnes.', N'Establecer las condiciones y requisitos específicos que deben cumplir los almacenes frigoríficos de carnes y despojos ,embalados o no, procedentes de los animales domésticos de las especies bovina, porcina, ovina, caprina y los solípedos domésticos que no se someten a ninguna manipulación salvo aquella necesarias para el almacenamiento de las mismas.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
