GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(9 AS Decimal(5, 0)), N'Sala de despiece de carne de aves de corral.', N'Establecer%20las%20condiciones%20y%20requisitos%20espec%EDficos%20que%20deben%20cumplir%20las%20salas%20de%20despiece%20de%20carne%20fresca%20de%20aves%20de%20corral%20dedicadas%20a%20la%20obtenci%F3n%20y%20comercializaci%F3n%20de%20partes%20de%20canales%20y%20sus%20despojos%20o%20carnes%20deshuesadas%20y%20su%20envasado%20y/o%20embalado.%20Todas%20ellas%20procedentes%20de%20aves%20dom%E9sticas%20de%20las%20siguientes%20especies%3A%20gallinas%2C%20patos%2C%20ocas%2C%20pavos%20y%20pintadas.%20', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(10 AS Decimal(5, 0)), N'Almacén frigorífico de carne de conejo y aves de caza de granja.', N'Establecer las condiciones y requisitos específicos que deben cumplir los almacenes frigoríficos de carne fresca de conejo doméstico y aves de caza de granja, que no se someten a ninguna manipulación salvo aquella necesarias para el almacenamiento de las mismas.
Entendiendo por aves de caza de granja aquellas aves no domésticas (distintas de gallinas, pavos, patos, pintadas y gansos), incluidas codornices, palomas, faisanes, perdices y aves corredoras, pero criadas como aves domésticas.
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(11 AS Decimal(5, 0)), N'Sala de despiece de carne de conejo y aves de caza de granja.', N'Establecer las condiciones y requisitos específicos que deben cumplir las salas de despiece de carne fresca de conejo doméstico y aves de caza de granja dedicadas a la obtención y comercialización de partes de canales y sus despojos o carnes deshuesadas y a su envasado y/o embalado. 
Entendiendo por aves de caza de granja aquellas aves no domésticas (distintas de gallinas, pavos, patos, pintadas y gansos), incluidas codornices, palomas, faisanes, perdices y aves corredoras, pero criadas como aves domésticas.
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(12 AS Decimal(5, 0)), N'Productos cárnicos.', N'Establecer las condiciones y requisitos específicos que deben reunir los establecimientos dedicados a la producción, troceado en su caso, envasado, almacenamiento y comercialización de:
Los productos cárnicos, siendo estos los elaborados a partir de carne y que sufre un tratamiento tecnológico que provoca la desaparición de las características de la carne fresca en la parte central de la superficie del corte. Quedando excluidos como tales las carnes sometidas a tratamiento de frío (refrigeración y/o congelación), las carnes picadas, las carnes en trozos de menos de 100 gr. y  los preparados de carne. En este sentido se consideran productos cárnicos a : los embutidos escaldados, cocidos, curados, secados, ahumados/ adobados, a las salazones cárnicas, a los adobados previa salazón, a las conservas (pasteurizadas o estereilizadas).
Quedan exceptuados los establecimientos de venta al por menor o locales contiguos a los puntos de venta.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(13 AS Decimal(5, 0)), N'Productos cárnicos de establecimientos con estructura no industrial.', N'Productos cárnicos de establecimientos con estructura no industrial.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(14 AS Decimal(5, 0)), N'Carne picada y preparados de carne.', N'
Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos (excepto los establecimientos de venta al por menor o locales adyacentes a los mismos) dedicados a la producción y comercialización de:
Carne picada, carne que ha sido sometida a una operación de picado en fragmentos o al paso por una máquina picadura continua. Si se destina a intercambios intracomunitarios, solamente se podrá obtener de las carnes provenientes de las especies bovina, porcina, ovina y caprina. Si se destina al mercado nacional, se podrá obtener de las carnes provenientes de las especies bovina, porcina, ovina, caprina, solípedos domésticos, gallinas, pavos, patos, pintadas, ocas, conejos, caza de granja y caza silvestre.
Preparados de carne, productos elaborados con carnes aptas para el consumo humano a las que se haya a¦adido productos alimenticios, condimentos o aditivos y/o que hayan sido sometidas a un tratamiento insuficiente para modificar la estructura celular de la carne en la parte central  de la superficie de corte y hacer desaparecer así las características de la carne fresca. Además de otros, se consideran preparados de carne las denominaciones de: crudos-adobados, salchichas crudas, butifarras frescas, longanizas frescas, chorizos frescos, hamburguesas y albóndigas. Si se destina a intercambios intracomunitarios, solamente se podrá obtener de las carnes provenientes de las especies bovina, porcina, ovina y caprina. Si se destina al mercado nacional, se podrá obtener de las carnes provenientes de las especies bovina, porcina, ovina, caprina, solípedos domésticos, gallinas, pavos, patos, pintadas, ocas, conejos, caza de granja y caza silvestre.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(15 AS Decimal(5, 0)), N'Preparados de carne de estructura no industrial.', N'Preparados de carne de estructura no industrial.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(16 AS Decimal(5, 0)), N'Carnicería-Salchichería', N'Establecer las condiciones y requisitos específicos que deben cumplir las carnicerías-salchicherías, entendiendo por éstas como aquellos establecimientos que:
1º.-Están formados por un local o conjunto de locales bajo titularidad única, que según su ubicación pueden:
a) Estar independientes
b) Estar integrados en una unidad comercial de mayor entidad, compartiendo servicios-vestuarios y elementos comunes de la unidad con otros establecimientos.
c) Ser una sección de un establecimiento polivalente, debiendo estar claramente separada e identificada del resto de secciones y podrán compartir los servicios-vestuarios y elementos comunes de dicho establecimiento polivalente.
2º.-Se dedican a la manipulación, preparación y presentación de carnes y despojos frescos (refrigerados o congelados) con o sin hueso en sus diferentes modalidades: fileteado, troceado, picado, mechado y otras análogas a estas. Además a la elaboración de: preparados de carne (frescos y crudos adobados) y/o embutidos de sangre (morcillas) y aquellos otros considerados tradicionales y que las autoridades sanitarias autoricen expresamente una vez valoradas las peticiones que las asociaciones de carniceros presenten. En caso de adoptar la aprobación de algún producto tradicional, se incluiría en el listado de productos a elaborar. También puede realizar el salazonado de tocino.
3º.-Las carnes y despojos que comercializan deben ser aptas para consumo humano, obtenidas en establecimientos autorizados y provenientes de animales domésticos (especies bovina, porcina, ovina, caprina, solípedos, gallinas, pavos, pintadas, patos, ocas y conejos) mamíferos terrestres y aves silvestres reproducidos, criados y sacrificados en cautividad, caza silvestre y reses de lidia de espectáculos taurinos. Según esta definición, y a efectos de clarificar las actividades, puede suceder que en mercados y galerías comerciales existan establecimientos que su actividad principal y casi única sea la de comercializar carnes de aves y elaborar preparados cárnicos frescos y crudos adobados con carnes de ave. En este caso su denominación sería la de POLLERIA-SALCHICHERIA, pero a efectos de requisitos higiénicos-sanitarios serían los recogidos en la presente IT.
4º.-Los productos que elaboran estos establecimientos solo pueden ser comercializadas en sus propias dependencias de venta al público y en las sucursales.
Entendemos por sucursales a las carnicerías que incorporan a los productos que comercializan, aquellos productos elaborados en otro considerado central, de la misma titularidad que ellos y localizados en la misma Comarca de Salud Pública donde se encuentra este establecimiento central. Asi tenemos según Territorio Histórico:
.- En Bizkaia: Interior, Gernika Lea-Artibay, Uribe Kosta, Margen Izquierda-Encartaciones y Bilbao.
.- En Guipúzcoa: Urola, Deba, Tolosa-Goierri, Bidasoa y Donostia.
.- En Araba: Araba Rural, Aiara y Rioja Alavesa.
5º.-Con excepción de los preparados cárnicos frescos y las carnes picadas, estos establecimientos solamente podrán suministrar a los establecimientos de comidas preparadas no sujetos a inscripción en el R.G.S.A. ubicados dentro del ámbito territorial de la Comarca de Salud Pública en la que se encuentra ubicado dicho establecimiento.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(17 AS Decimal(5, 0)), N'Lonjas pesqueras y mercados al por mayor.', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos donde se realiza la exposición y primera venta al por mayor de productos de la pesca( lonja pesquera) o los centros de concentración de productos de la pesca, en los que únicamente se efectúe la exposición y venta al por mayor (mercado al por mayor).', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(18 AS Decimal(5, 0)), N'Buques pesqueros.', N'Buques pesqueros.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(19 AS Decimal(5, 0)), N'Transformación de productos de la pesca.', N'Establecer las condiciones y requisitos específicos que, de manera general, deben cumplir los establecimientos en tierra en que se preparen, transformen, refrigeren, congelen, envasen y/o embalen, o depositen productos pesqueros. No se consideran establecimientos los mercados de subastas ni los mercados al por mayor en los que únicamente se efectúen la exposición y la venta al por mayor, ni las depuradoras de moluscos y cetáreas, ni los buques, ni los establecimientos dedicados únicamente al almacenamiento frigorífico, ni los comercios al por menor de productos pesqueros.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(20 AS Decimal(5, 0)), N'Centros de expedición y de depuración de molusculos bivalvos.', N'Establecer los requisitos que deben cumplir los centros de expedición y de depuración de moluscos bivalvos ( moluscos lamelibranquios que se alimentan por filtración ), entendiéndose por CENTRO DE EXPEDICIÓN a toda instalación terrestre o flotante, homologada, en la que se reciben, acondicionan (los moluscos que no precisan depuración se almacenan en tanques con agua de mar limpia), lavan, limpian, calibran y envasan moluscos bivalvos aptos para consumo humano y entendiéndose por CENTRO DE DEPURACIÓN, los establecimientos homologados que disponen de estanques alimentados por agua de mar limpia de manera natural o depurada mediante un tratamiento adecuado, en los que se mantienen los moluscos bivalvos vivos durante el tiempo necesario para que puedan eliminar la contaminación de origen microbiano, con el fin de convertirlos en aptos para el consumo humano.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(21 AS Decimal(5, 0)), N'Pescaderías.', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos dedicados a la venta al por menor de productos de la pesca destinados al consumo humano.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(22 AS Decimal(5, 0)), N'Almacén de pesca.', N'Establecer las condiciones y requisitos que de manera específica deben cumplir los establecimientos dedicados al almacenamiento de productos de la pesca bien refrigerados o bien congelados y/o aquellos que se dedican a la congelación de productos pesqueros. Asimismo, se incluyen aquellos establecimientos que realizan únicamente el reenvasado de productos pesqueros.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(23 AS Decimal(5, 0)), N'Centro de cetárea.', N'Establecer los requisitos que deben cumplir los establecimientos dedicados a mantener , envasar y distribuir, los crustáceos vivos, durante un periodo de tiempo bajo condiciones controladas en agua de mar limpia, en tanques, balsas, o parques flotantes. ', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
