INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(26 AS Decimal(5, 0)), N'Elaboración de ovoproductos.', N'Establecer las condiciones y requisitos que de manera específica deben cumplir los establecimientos elaboradores de ovoproductos, (productos obtenidos del huevo, sus componentes o sus mezclas, sin cáscara ni membranas, completados o no con productos alimenticios o aditivos y en estado líquido, concentrado, desecado, congelado o ultra congelado), desde la recepción de materias primas hasta el etiquetado y distribución del producto final.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
