INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(28 AS Decimal(5, 0)), N'Tubérculos (transformación y envasado de patata fresca refrigerada).', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos de transformación / procesado de patata fresca: Pelado, troceado, desfeculado, ba¦o de tratamiento (salmuera y antioxidante), escurrido, envasado, embalado y conservación frigorífica.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(29 AS Decimal(5, 0)), N'Establecimientos elaboradores de pan y panes especiales.', N'Establecer las condiciones y requisitos específicos que deben cumplir los elaboradores y fabricantes de productos de panadería.
Se consideran elaboradores y fabricantes de productos de panadería, aquellos establecimientos o industrias que dedican su actividad a la elaboración de pan y panes especiales.
Se define como pan, el producto resultante de la cocción de una masa obtenida por la mezcla de harina de trigo y agua potable, con o sin adición de sal comestible, fermentada por especies de microorganismos propios de la fermentación panadería. Se considera pan común el definido anteriormente, al que solamente se le pueden a¦adir los coadyuvantes tecnológicos y aditivos autorizados para este tipo de pan.
Se considera pan especial el no incluido en la definición anterior y que reúna alguna de las condiciones siguientes: 
Que se haya incorporado cualquier aditivo y/o coadyuvante tecnológico autorizado para panes especiales.
Que se haya utilizado como materia harina enriquecida.
Que se haya a¦adido cualquier ingrediente que eleve su valor nutritivo.
Que no lleve microorganismos propios de la fermentación, voluntariamente a¦adidos.
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(30 AS Decimal(5, 0)), N'Pastas alimenticias.', N'Pastas alimenticias.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(31 AS Decimal(5, 0)), N'Minorista de panadería.', N'Minorista de panadería.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(32 AS Decimal(5, 0)), N'Pastelerías.', N'Establecer las condiciones y requisitos específicos que deben cumplir los obradores de pastelería.
Obradores de pastelería: son aquellos establecimientos, de carácter industrial o no, que elaboran, envasan, almacenan, distribuyen y/o importan productos de pastelería.
Los productos de pastelería son aquellos elaborados, fermentados o no, de diversa forma, tama¦o y composición, integrados fundamentalmente por harinas, féculas, azúcares, grasas comestibles y otros productos alimenticios y alimentarios como sustancias complementarias.
Los obradores de pastelería se diferenciarán en industriales o no industriales. Tendrán la consideración de industriales aquellos en los que se den estas circunstancias:
.- Comercializan sus productos por terceros, además o no de en despachos de su propiedad.
.- Tienen distribuciones amplias, incluyendo venta en sector minorista, fuera de su municipio, y   frecuentemente de productos envasados.
.- Sus volúmenes de producción son grandes.
Las condiciones de etiquetado y trazabilidad deben cumplirlas los establecimientos de tipo industrial que comercializan productos envasados y embalados (por ejemplo, ¦astas, galletas, etc.)
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(33 AS Decimal(5, 0)), N'Establecimientos envasadores de azúcar.', N'Establecer las condiciones y requisitos que deben cumplir de forma específica los establecimientos dedicados a la actividad de envasado de azúcar.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(34 AS Decimal(5, 0)), N'Establecimientos de extracción y envasado de miel.', N'Establecer las condiciones y requisitos que deben cumplir de forma específica los establecimientos dedicados a la actividad de extracción y/o envasado de miel (néctar y mielada).
Las mieles se clasifican en:
-Mieles de consumo directo
Dependiendo de su origen floral se denominará con el término miel seguido de flores, milflores, la especie unifloral o de mielada. La que proceda de mieles de flores y de mielada se denominará miel de flores y mielada.
.La miel en panales, miel en secciones y la miel con trozos de panal miel escurrida, miel centrifugada, miel prensada y miel filtrada.
-Las mieles con destino a la industria se denominarán o miel de industria.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(35 AS Decimal(5, 0)), N'Establecimientos elaboradores de turrones y mazapanes.', N'Establecer las condiciones y requisitos que deben cumplir de forma específica los establecimientos dedicados a la actividad de elaboración de turrones y mazapanes.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(36 AS Decimal(5, 0)), N'Comedores colectivos institucionales que elaboran comidas.', N'Establecer las condiciones y requisitos específicos que deben cumplir los comedores colectivos institucionales que elaboran comidas en sus instalaciones, de acuerdo a su riesgo sanitario.
Comedores institucionales: comedores colectivos que forman parte de empresas, centros o instituciones como actividad accesoria de éstos. A efectos de su autorización sanitaria de funcionamiento, se clasifican en comedores escolares, comedores de empresa, comedores de residencias, cocinas de hospitales o clínicas y otros comedores institucionales.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(37 AS Decimal(5, 0)), N'Comedores colectivos institucionales sin elaboración comidas.', N'Establecer las condiciones y requisitos específicos que deben cumplir los comedores colectivos institucionales que no elaboran comidas, de acuerdo a su riesgo sanitario.
Comedores institucionales: comedores colectivos que forman parte de empresas, centros o instituciones como actividad accesoria de éstos. A efectos de su autorización sanitaria de funcionamiento, se clasifican en comedores escolares, comedores de empresa, comedores de residencias, cocinas de hospitales o clínicas y otros comedores institucionales.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(38 AS Decimal(5, 0)), N'Elaboración de platos preparados no industriales Grupo I.', N'Establecer las condiciones y requisitos especificos que deben cumplir los establecimientos de elaboración de platos preparados no industriales, de acuerdo a su riesgo sanitario.
Los establecimientos de elaboración de platos preparados no industriales del grupo I son aquellos cuya actividad sea facilitar comidas preparadas de bajo riesgo que no se consumen en el mismo local donde se elaboran, pudiendo ser vendidas al consumidor final para su consumo fuera del establecimiento de elaboración, o suministradas al mismo en su domicilio particular.
Se incluyen en este grup las pizzerías, hamburgueserías, bacaterías, los establecimientos de elaboración y venta de pollos asados y asimilables.
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(39 AS Decimal(5, 0)), N'Cocinas centrales.', N'Establecer las condiciones y requisitos específicos que deben cumplir las cocinas centrales, de acuerdo a su riesgo sanitario.
Cocina central: establecimiento que elabora comidas completas para su distribución a colectividades, entendidas éstas como entidades sociales públicas o privadas que agrupan a un conjunto de individuos con características similares (empresas, colegios, residencias, hospitales, asociaciones o similares) que demandan un servicio de comidas preparadas.
Será considerado también colectividad, el conjunto de individuos agrupados con motivo de celebraciones, banquetes y similares.
La distribución de dichas comidas podrá realizarse en caliente o en frío para su consumo directo sin tratamiento térmico adicional o tras una regeneración térmica. 
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(40 AS Decimal(5, 0)), N'Industrias de platos preparados.', N'Industrias de platos preparados.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(42 AS Decimal(5, 0)), N'Agua de bebida envasada.', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos relacionados con el envasado, almacenamiento y comercialización de aguas de bebida envasadas.
Se entienden como aguas de bebida envasadas las siguientes:
Aguas minerales naturales: aquellas bacteriológicamente sanas que tengan su origen en un estrato o yacimiento subterráneo y que broten de un manantial en uno o varios puntos de alumbramiento, naturales o perforados.
Éstas pueden distinguirse claramente de las restantes aguas potables por su naturaleza caracterizada por su contenido en minerales, oligoelementos y otros componentes y en ocasiones por determinados defectos.
Aguas de manantial: son las potables de origen subterráneo que emergen espontáneamente en la superficie de la tierra o se captan mediante labores practicadas al defecto, con las características naturales de pureza que permiten su consumo.
Aguas preparadas: son las sometidas a tratamientos fisicoquímicos necesarios para su potabilización, pudiendo ser Potables Preparadas cuando procedan de manantial o captación o de Abastecimiento Público Preparadas en el supuesto de tener dicha procedencia.
Aguas de consumo público envasadas: son aquellas aguas potables de consumo público, envasadas coyunturalmente para distribución domiciliaria, con el único objeto de suplir ausencias o insuficiencias accidentales de las aguas de consumo público distribuidas por la red general.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(43 AS Decimal(5, 0)), N'Fabricación de hielo.', N'Establecer%20las%20condiciones%20y%20requisitos%20espec%EDficos%20que%20deben%20cumplir%20los%20establecimientos%20relacionados%20con%20la%20producci%F3n%20y%20comercializaci%F3n%20del%20hielo.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(44 AS Decimal(5, 0)), N'Establecimientos elaboradores de helados y mezclas envasadas para congelar.', N'Establecer las condiciones específicas a las que han de atenerse los establecimientos dedicados a la elaboración, envasado y circulación de helados y mezclas envasadas para congelar, incluyéndose  los establecimientos de producción limitada y los que elaboran para  venta en el propio establecimiento.
Los establecimientos de producción limitada son aquellos: cuya producción sea inferior a 400.000 litros de leche al a¦o.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(45 AS Decimal(5, 0)), N'Bebidas refrescantes (elaboración y envasado).', N'Establecer las condiciones y requisitos específicos que deben cumplir las industrias de elaboración y envasado de bebidas refrescantes.
Se entiende por bebida refrescante la preparada con agua potable y los ingredientes y demás productos autorizados, adicionada o no de anhídrido carbónico.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(46 AS Decimal(5, 0)), N'Bebidas alcohólicas: Vino/txakoli (elaboración y/o envasado).', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos de elaboración y/o envasado de VINO / TXAKOLI.
Se entiende por vino el producto obtenido exclusivamente por la fermentación alcohólica, total o parcial, de uva fresca, estrujada o no, o de mosto de uva. Tendrá un grado alcohólico volumétrico adquirido no inferior al 8,5% así como un grado alcohólico volumétrico total no superior al 15%.
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(47 AS Decimal(5, 0)), N'Bebidas alcohólicas: Sidra  natural (elaboración y envasado).', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos de elaboración, embotellado y almacenamiento de sidra natural. Entendiéndose por tal, la elaborada siguiendo las prácticas tradicionales, sin adición de azúcares, que contiene gas carbónico de origen endógeno exclusivamente. Su graduación alcohólica adquirida será superior a  4%B45 grados.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(48 AS Decimal(5, 0)), N'Bebidas espirituosas (elaboración y/o envasado).', N'Establecer las condiciones y requisitos específicos que deben cumplir las industrias de elaboración y/o envasado de bebidas espirituosas, entendiendo por tal el liquido alcohólico destinado al consumo humano de características organolepticas especiales, con un grado alcohólico mínimo de 15 % vol, obtenido:
Directamente por destilación (en presencia o no de aromas) de productos naturales fermentados.
Por maceración de sustancias vegetales o adición de aromas, azucares u otros edulcorantes al alcohol etílico de origen agrícola, a un destilado de origen agrícola o a un aguardiente.
Por mezcla de una o varias bebidas espirituosas con alcohol etílico de origen agrícola, destilados, aguardientes u otras bebidas alcohólicas.
Entre ellas podemos citar: El Ron, Whisky, Cognac, Brandy, Orujo, Pacharán, Ginebra, Anís y derivados, diversos Licores y Aguardientes (de frutas, de huevo, de café, Vodka, Tequila, Pastís,?), Ponches y bebidas aperitivas, etc.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(49 AS Decimal(5, 0)), N'Bebidas alcohólicas: Cerveza (elaboración y/o envasado).', N'Establecer las condiciones y requisitos específicos que deben cumplir las industrias de elaboración y/o envasado de cerveza y malta líquida, considerada como la bebida resultante de la fermentación alcohólica, mediante levadura seleccionada, de un mosto procedente de malta de cebada, solo o mezclado con otros productos amiláceos transformables en azúcares por digestión enzimática, adicionado con lúpulo y/o sus derivados y sometido a un proceso de cocción.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(50 AS Decimal(5, 0)), N'Almacenes frigoríficos.', N'Establecer las condiciones y requisitos que de manera específica deben cumplir los establecimientos de almacenamiento frigorífico de alimentos y productos alimentarios.
Quedan exceptuadas aquellas actividades que pudieran realizarse en los almacenes frigoríficos y que tengan establecidas normas específicas, a través de sus Reglamentaciones Técnico Sanitarias.

', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(51 AS Decimal(5, 0)), N'Almacenes no frigoríficos.', N'Establecer las condiciones y requisitos que de manera específica deben cumplir los establecimientos de almacenamiento  no frigorífico de alimentos y productos alimentarios.
Quedan exceptuadas aquellas actividades que pudieran realizarse en los almacenes y que tengan establecidas normas específicas, a través de sus Reglamentaciones Técnico Sanitarias.

', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(52 AS Decimal(5, 0)), N'Establecimientos no permanentes.', N'Establecer las condiciones y requisitos específicos que se deben cumplir en el ejercicio de la actividad de venta en establecimientos no permanentes, entendiendo como tal actividad la realizada por vendedores habituales u ocasionales de un establecimiento comercial, en puestos o instalaciones desmontables, así como en vehículos. Se incluye también la venta en los quioscos como establecimiento ubicado en la vía pública de forma permanente.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(53 AS Decimal(5, 0)), N'Grasas y aceites vegetales comestibles.', N'Establecer las condiciones y requisitos específicos que deben cumplir las industrias de elaboración y/o envasado, circulación y comercio de grasas comestibles animales, vegetales y anhidras y aceites vegetales comestibles.
Grasas comestibles son los productos de origen animal, vegetal o sus mezclas, cuyos componentes principales sean glicéridos de los ácidos grasos, pudiendo tener otros componentes menores.
Grasas animales son las obtenidas, por distintos procedimientos, a partir de diversos depósitos adiposos de determinados animales en adecuado estado sanitario Manteca de cerdo, grasa de cerdo fundida, primeros jugos, sebos comestibles y otras grasas animales.
Grasas vegetales: son las obtenidas, por distintos procedimientos, de frutos o semillas sanas y limpias Manteca de coco, grasa de palmiste, manteca de palma, manteca de cacao y otras grasas vegetales.
Grasas anhidras: las constituidas por aceites y/o grasas comestibles y sus mezclas, de aspecto homogéneo y con una humedad no superior a 0,5 por 100. Estas grasas se destinan a la alimentación a través de industrias alimentarias o para uso doméstico en preparaciones culinarias.
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
