INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(66 AS Decimal(5, 0)), N'Comercio minorista de alimentación.', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos dedicados a la venta al por menor de productos alimenticios destinados al consumo humano, incluidos pan y pasteles en establecimientos sin elaboración, y carne, pescado, y precocinados cuando se trate de productos envasados sin manipulación en el establecimiento y aunque la venta se realice en instalaciones de comercio mayorista, fábricas u otros lugares de producción o sus anejos y otros establecimientos cuya actividad principal sea distinta y los integrados en recintos comerciales colectivos, incluyendo todo tipo de todo tipo de productos al por menor sin manipulación.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(67 AS Decimal(5, 0)), N'Patatas fritas y productos de aperitivo (elaboración y envasado).', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos dedicados a la elaboración y comercialización (en instalaciones fijas o en no permanentes) de patatas fritas y productos de aperitivo, entendiendo por estos últimos aquellos preparados de utilización básicamente fruitiva como aperitivos, obtenidos por secado, tostación, extrusión, fritura, troquelado o procedimientos similares y a partir de  materias primas de origen animal o vegetal (cortezas, snacks, palitos, prettzels, lazos y similares).', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(68 AS Decimal(5, 0)), N'Comedores colectivos: Establecimientos de hostelería grupo 0. ', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos de hostelería del grupo 0.
Los establecimientos de hostelería del grupo 0 son establecimientos que no elaboran alimentos, sino que solo sirven bebidas y/o alimentos. Se incluyen los establecimientos que exponen y sirven productos elaborados por industrias autorizadas.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(69 AS Decimal(5, 0)), N'Comedores colectivos: Establecimientos de hostelería grupo I.', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos de hostelería del grupo I.
Los establecimientos de hostelería del grupo I son aquellos comedores colectivos que elaboran alimentos para su consumo inmediato, pero sin servicio de comidas completas en locales o zonas al efecto. Se incluyen en este grupo, los bares con elaboración de pinchos y/o platos combinados, pizzerías, hamburgueserías, bocaterías, cafeterías y asimilables.
 También se incluyen establecimientos que elaboran menús simples de bajo riesgo en peque¦as cantidades, siendo el aprovisionamiento de materias primas perecederas ajustadas a su consumo diario y manteniendo estas condiciones estables a lo largo de la semana y en cualquier época del a¦o.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(70 AS Decimal(5, 0)), N'Comedores colectivos: Establecimientos de hostelería grupo II.', N'Establecer%20las%20condiciones%20y%20requisitos%20espec%EDficos%20que%20deben%20cumplir%20los%20establecimientos%20de%20hosteler%EDa%20del%20grupo%20II%2C%20de%20acuerdo%20a%20su%20riesgo%20sanitario.%0D%0ALos%20establecimientos%20de%20hosteler%EDa%20del%20grupo%20II%20son%20aquellos%20comedores%20colectivos%20que%20elaboran%20y%20sirven%20men%FAs%20o%20comidas%20completas%2C%20muy%20variadas%2C%20con%20ingredientes%20de%20diversa%20naturaleza%20y%20origen%2C%20que%20sufren%20preparaciones%20tambi%E9n%20variadas%2C%20y%20con%20servicio%20de%20los%20mismos%20en%20un%20comedor%20o%20zona%20habilitada%20al%20efecto.%20Se%20incluyen%20establecimientos%20de%20hosteler%EDa%20con%20men%FA%20y/o%20carta%2C%20y%20asimilables.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'2019-03-12' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(71 AS Decimal(5, 0)), N'Comedores colectivos: Establecimientos de hostelería grupo III.', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos de hostelería del grupo III, de acuerdo a su riesgo sanitario.
Los establecimientos de hostelería del grupo III son aquellos comedores colectivos que elaboran productos muy variados en cuanto a preparación, ingredientes, coberturas y nivel de riesgo sanitario, pero en grandes cantidades, con preparación previa en gran parte y a gran número de comensales simultáneamente (capacidad superior a 150 comensales).', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(72 AS Decimal(5, 0)), N'Almacén frigorífico de carnes de mamíferos de caza de granja.', N'Establecer las condiciones y requisitos específicos que deben cumplir los almacenes frigoríficos de carnes y despojos ,embalados o no, procedentes de mamíferos de caza de granja que no se someten a ninguna manipulación salvo aquella necesarias para el almacenamiento de las mismas.
Entendiendo por mamíferos de caza de granja aquellos mamíferos terrestres no considerados domésticos, distintos de los bovinos (incluidas las especies Bubalus bubalis y Bison bison), porcinos, ovinos, caprinos y solípedos domésticos, pero criados como animales domésticos. Sin embargo no se considerarán caza de granja aquellos mamíferos silvestres que vivan en un territorio cerrado en condiciones de libertad semejantes a las de caza silvestre.
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(73 AS Decimal(5, 0)), N'Sala de despiece de carnes de mamíferos de caza de granja.', N'Establecer las condiciones y requisitos específicos que deben cumplir las salas de despiece de carne fresca de mamíferos de caza de granja dedicadas a la obtención y comercialización de porciones más peque¦as que las canales, las medias canales y las medias canales despiezadas en un máximo de tres piezas o los cuartos, al deshuese de las mismas, su envasado o no y a la comercialización de despojos (enteros envasados o no) o fileteados. 
Entendiendo por mamíferos de caza de granja aquellos mamíferos terrestres no considerados domésticos, distintos de los bovinos (incluidas las especies Bubalus bubalis y Bison bison), porcinos, ovinos, caprinos y solípedos domésticos, pero criados como animales domésticos. Sin embargo no se considerarán caza de granja aquellos mamíferos silvestres que vivan en un territorio cerrado en condiciones de libertad semejantes a las de caza silvestre.
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(74 AS Decimal(5, 0)), N'Establecimientos procesadores de conservas y semiconservas vegetales y zumos.', N'Establecer los requisitos técnico-sanitarios que tienen que cumplir los establecimientos dedicados a la actividad de elaboración y comercialización de conservas y semiconservas vegetales incluidos los zumos de frutas y néctares.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(75 AS Decimal(5, 0)), N'Mataderos de poca capacidad.', N'Mataderos de poca capacidad.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
