INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(77 AS Decimal(5, 0)), N'Establecimientos procesadores de aceitunas y encurtidos.', N'Establecer los requisitos técnico-sanitarios que tienen que cumplir los establecimientos dedicados a la actividad de almacenamiento y elaboración de frutas y hortalizas secas, desecadas y deshidratadas; elaboración de aceitunas y encurtidos.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(78 AS Decimal(5, 0)), N'Centros de recogida de leche y centros de normalización.', N'Establecer las condiciones y requisitos específicos que, además de los indicados de forma general, deben cumplir de forma especifica los establecimientos dedicados a la recogida y normalización de leche cruda.
Se entiende por leche cruda la leche de vaca, oveja, cabras o búfalas que no haya sido calentada a una temperatura superior a 40º C ni sometida a un tratamiento de efecto equivalente.
Los Centros de recogida de leche son establecimientos donde se puede recoger la leche cruda procedente de las explotaciones y, en su caso, enfriarse y purificarse. De allí es llevada a los establecimientos de tratamiento térmico o de transformación en productos lácteos. 
Los Centros de normalización son establecimientos no ligados a un centro de recogida ni a un establecimiento de tratamiento o transformación en los que la leche cruda procedente de las explotaciones puede someterse a un desnatado o a una modificación del contenido en componentes normales de la leche.
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(79 AS Decimal(5, 0)), N'Envasadores de leche cruda.', N'Establecer las condiciones y requisitos específicos que, además de los indicados de forma general, deben cumplir de forma especifica los establecimientos dedicados a la producción y comercialización de leche cruda.
Son establecimientos anexos a explotaciones de producción en los que se procede al envasado de leche cruda para su comercialización dentro de la CAPV.  Generalmente son establecimientos de poca producción 
Se entiende por establecimientos de producción limitada   aquellos cuya producción anual es inferior a 750.000 litros en leche de vaca, 250.000 litros en leche de oveja, 350.000 litros en leche de cabra, o 700.000 litros en caso de mezcla de varias especies.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(80 AS Decimal(5, 0)), N'Establecimientos de tratamiento térmico de leche para consumo.', N'Establecer las condiciones y requisitos específicos que, además de los indicados de forma general, deben cumplir de forma especifica los establecimientos dedicados a la producción y comercialización de leche de consumo tratada térmicamente. 
 Son establecimientos en los que se trata térmicamente la leche cruda procedente de las explotaciones de producción, de centros de recogida o de centros de normalización. Se entiende por tratamiento térmico cualquier tratamiento por calentamiento que, inmediatamente después de su aplicación, tenga como consecuencia una reacción negativa a la prueba de la fosfatasa.
Se entiende por leche de consumo tratada térmicamente la leche de consumo destinada a la venta al consumidor final y a las colectividades, obtenida mediante tratamiento térmico y que se presente en las formas de leche pasteurizada, leche pasteurizada sometida a alta pasteurización, leche esterilizada y leche UHT.
Se entiende por terminación el calentamiento de la leche cruda durante 15 segundos como mínimo, a una temperatura comprendida entre 57º C y 68º C, de forma que la leche, después de ese tratamiento, reaccione positivamente a la prueba de la fosfatasa.
Se entiende por establecimientos de producción limitada   aquellos cuya producción anual es inferior a 750.000 litros en leche de vaca, 250.000 litros en leche de oveja, 350.000 litros en leche de cabra, o 700.000 litros en caso de mezcla de varias especies.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(82 AS Decimal(5, 0)), N'Elaboración de masas fritas.', N'Elaboración de masas fritas', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
