INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(95 AS Decimal(5, 0)), N'Preparados alimenticios para regímenes dietéticos y/o especiales.', N'Establecer las condiciones y requisitos que de manera específica deben cumplir los establecimientos dedicados a la actividad de elaboración, envasado y comercialización de los preparados alimenticios dietéticos y/o destinados a una alimentación especial, así como las características específicas que deben cumplir los productos incluidos en este grupo de alimentos, de acuerdo con la definiciones que figuran en el anexo 2.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(97 AS Decimal(5, 0)), N'Carnicerías', N'Establecer las condiciones y requisitos específicos que deben cumplir las carnicerías, entendiendo por éstas como aquellos establecimientos que:
1º.Están formados por un local o conjunto de locales bajo titularidad única, que según su ubicación pueden:
a)Estar independientes
b)Estar integrados en una unidad comercial de mayor entidad, compartiendo servicios-vestuarios y elementos comunes de la unidad con otros establecimientos.
c)Ser una sección de un establecimiento polivalente, debiendo estar claramente separada e identificada del resto de secciones y podrán compartir los servicios-vestuarios y elementos comunes de dicho establecimiento polivalente.
2º.Se dedican a la manipulación, preparación y presentación de carnes y despojos frescos (refrigerados o congelados) con o sin hueso en sus diferentes modalidades: fileteado, troceado, picado, mechado y otras análogas a estas, para suministro directamente al consumidor final bien en venta directa o reparto a domicilio, teniendo en cuenta además lo recogido en el punto nº 6 de este apartado.
3º.Las carnes y despojos que comercializan deben ser aptas para consumo humano, obtenidas en establecimientos autorizados y provenientes de animales domésticos (especies bovina, porcina, ovina, caprina, solípedos, gallinas, pavos, pintadas, patos, ocas y conejos) mamíferos terrestres y aves silvestres reproducidos, criados y sacrificados en cautividad, caza silvestre y reses de lidia de espectáculos taurinos. Según esta definición, y a efectos de clarificar las actividades, puede suceder que en mercados y galerías comerciales existan establecimientos que su actividad principal y casi única sea la de comercializar carnes de aves. En este caso su denominación sería la de POLLERIA, pero a  efectos de requisitos higiénico-sanitarios serian los recogidos en la presente IT. 
4º.No tienen autorización para la elaboración propia de preparados cárnicos (frescos, crudos-adobados), productos cárnicos, otros productos de origen animal y platos cocinados cárnicos, pero sí para la comercialización de éstos si proceden de industrias autorizadas, o estas carnicerías actúan como sucursales de otro establecimiento considerado central.
5º.Entendemos por sucursales a las carnicerías que incorporan a los productos que comercializan, aquellos productos elaborados en otro considerado central, de la misma titularidad que ellos y localizados en la misma Comarca de Salud Pública donde se encuentra este establecimiento central. Asi tenemos según Territorio Histórico:
·En Bizkaia: Interior, Gernika Lea-Artibay, Uribe Kosta, Margen Izquierda-Encartaciones y Bilbao.
·En Guipúzcoa: Urola, Deba, Tolosa-Goierri, Bidasoa y Donosita.
·En Araba: Araba Rural, Aiara y Rioja Alavesa.
6º. Con excepción de los preparados cárnicos frescos y las carnes picadas, estos establecimientos solamente podrán suministrar a los establecimientos de comidas preparadas no sujetos a inscripción en el R.G.S.A. ubicados dentro del ámbito territorial de la Comarca de Salud Pública en la que se encuentra ubicado dicho establecimiento.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(98 AS Decimal(5, 0)), N'Carnicería-Charcutería', N'Establecer las condiciones y requisitos específicos que deben cumplir las carnicerías-charcuterías, entendiendo por éstas como aquellos establecimientos que:
1º.Están formados por un local o conjunto de locales bajo titularidad única, que según su ubicación pueden:
a)Estar independientes
b)Estar integrados en una unidad comercial de mayor entidad, compartiendo servicios-vestuarios y elementos comunes de la unidad con otros establecimientos.
c)Ser una sección de un establecimiento polivalente, debiendo estar claramente separada e identificada del resto de secciones y podrán compartir los servicios-vestuarios y elementos comunes de dicho establecimiento polivalente.
2º.Se dedican a la manipulación, preparación y presentación de carnes y despojos frescos (refrigerados o congelados) con o sin hueso en sus diferentes modalidades: fileteado, troceado, picado, mechado y otras análogas a estas. Además podrán elaborar: 
- preparados de carne (frescos y crudas adobados) 
- productos cárnicos
- otros productos de origen animal
- platos cocinados cárnicos
- productos tradicionales que las autoridades sanitarias autoricen expresamente, una vez valoradas las peticiones que las asociaciones de carniceros presenten.
Las carnes y despojos que comercializan deben ser aptas para consumo humano, obtenidas en establecimientos autorizados y provenientes de animales domésticos (especies bovina, porcina, ovina, caprina, solípedos, gallinas, pavos, pintadas, patos, ocas y conejos) mamíferos terrestres y aves silvestres reproducidos, criados y sacrificados en cautividad, caza silvestre y reses de lidia de espectáculos taurinos.
3º.Los productos que elaboran estos establecimientos solo pueden ser comercializadas en sus propias dependencias de venta al público y en las sucursales.
Entendemos por sucursales a las carnicerías que incorporan a los productos que comercializan, aquellos productos elaborados en otro considerado central, de la misma titularidad que ellos y localizados en la misma Comarca de Salud Pública donde se encuentra este establecimiento central. 
Asi tenemos según Territorio Histórico:
En Bizkaia: Interior, Gernika Lea-Artibay, Uribe Kosta, Margen Izquierda-Encartaciones y Bilbao.
En Guipúzcoa: Urola, Deba, Tolosa-Goierri, Bidasoa y Donostia.
En Araba: Araba Rural, Aiara y Rioja Alavesa.
5º. Con excepción de los preparados cárnicos frescos y las carnes picadas, estos establecimientos solamente podrán suministrar a los establecimientos de comidas preparadas no sujetos a inscripción en el R.G.S.A. ubicados dentro del ámbito territorial de la Comarca de Salud Pública en la que se encuentra ubicado dicho establecimiento.
', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(99 AS Decimal(5, 0)), N'Elaboración de platos preparados no industriales Gurpo II', N'Establecer las condiciones y requisitos específicos que deben cumplir los establecimientos de elaboración de platos preparados no industriales del grupo II, de acuerdo a su riesgo sanitario.
Los establecimientos de elaboración de platos preparados no industriales del grupo II son aquellos cuya actividad sea facilitar comidas preparadas que no se consumen en el mismo local donde se elaboran, pudiendo ser vendidas al consumidor final para su consumo fuera del establecimiento de elaboración, o suministradas al mismo en su domicilio particular.
Son establecimientos que elaboran y venden comidas completas, muy variadas, con ingredientes de diversa naturaleza y origen, que sufren preparaciones también variadas', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(100 AS Decimal(5, 0)), N'Otros productos de origen animal.', N'Establecer las condiciones y requisitos específicos que deben reunir los establecimientos dedicados a la producción/transformación, envasado, almacenamiento y comercialización de, otros productos de origen animal siendo estos: 
%u2022Las grasas animales fundidas: grasas obtenidas por fundición mediante tratamiento térmico de la carne incluyendo los huesos, y destinados a consumo humano.
%u2022Los chicharrones: residuos proteicos de la fundición de grasas, tras la separación parcial de la grasa y el agua.
%u2022Las gelatinas: la proteína natural, soluble, gelificante o no, obtenida mediante hidrólisis parcial del colágeno producido a partir de huesos, pieles, tendones y nervios de animales.
%u2022El colágeno: producto a base de proteína obtenido a partir de los huesos, pieles, tendones y nervios de animales y fabricado según lo establecido en la normativa correspondiente.
%u2022Estómagos, vejigas e intestinos tratados: han sido sometidos a tratamientos como salado, calentamiento o secado después de haberse extraído y limpiarlos.
%u2022También están dentro de este epígrafe: los extractos de carne, harinas de carne, corteza de cerdo en polvo, sangre salada, sangre seca, el plasma sanguíneo salado o seco, todo con destino a consumo humano.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(101 AS Decimal(5, 0)), N'Queserías tradicionales y otras', N'Establecer las condiciones y requisitos específicos que, además de los indicados de forma general, deben cumplir de forma especifica los establecimientos en los que se elaboran quesos  de características tradicionales y otros tipos, elaborados a partir de leche cruda y que pasan un proceso de maduración superior a 60 días antes de su venta y consumo.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(102 AS Decimal(5, 0)), N'Establecimientos de elaboración de productos lácteos.', N'Establecer las condiciones y requisitos específicos que, además de los indicados de forma general, deben cumplir de forma especifica los establecimientos en los que se procede al tratamiento, transformación y envasado de productos lácteos.
Se entiende por producto lácteo los productos a base de leche, teniendo en cuenta que se pueden a¦adir sustancias para su elaboración siempre que no sustituyan total o parcialmente alguno de de los componentes de la leche y teniendo en cuenta que la leche sea el componente esencial.
Se entiende por leche destinada a la elaboración de productos lácteos la leche cruda líquida o congelada, que haya sufrido o no algún tratamiento físico autorizado como por ejemplo un tratamiento térmico o una termización y que su composición haya sido modificada o no adición o sustracción de componentes normales de la leche.
Se entiende por establecimientos de características tradicionales o de producción limitada   aquellos cuya producción anual es inferior a 750.000 litros en leche de vaca, 250.000 litros en leche de oveja, 350.000 litros en leche de cabra, o 700.000 litros en caso de mezcla de varias especies. ', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(103 AS Decimal(5, 0)), N'Elaboración de harina de baja producción', N'Establecer las condiciones y requisitos que de manera general, deben cumplir estos establecimientos alimentarios, dedicados a la molienda de granos de forma no industrial con excasa actividad de producción y ambito local. ', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'2022-03-29' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(105 AS Decimal(5, 0)), N'Establecimiento con autorización sanitaria para tratamiento térmico de leche', N'Establecer las condiciones y requisitos específicos que, además de los indicados de forma general, deben cumplir de forma especifica los establecimientos dedicados a la producción y comercialización de leche de consumo tratada térmicamente. Son establecimientos en los que se trata térmicamente la leche cruda procedente de las explotaciones de producción, de centros de recogida o de centros de normalización. Se entiende por tratamiento térmico cualquier tratamiento por calentamiento que, inmediatamente después de su aplicación, tenga como consecuencia una reacción negativa a la prueba de la fosfatasa. Se entiende por leche de consumo tratada térmicamente la leche de consumo destinada a la venta al consumidor final y a las colectividades, obtenida mediante tratamiento térmico y que se presente en las formas de leche pasteurizada, leche pasteurizada sometida a alta pasteurización, leche esterilizada y leche UHT. Se entiende por terminación el calentamiento de la leche cruda durante 15 segundos como mínimo, a una temperatura comprendida entre 57 grados Centigrados y 68 grados Centigrados, de forma que la leche, después de ese tratamiento, reaccione positivamente a la prueba de la fosfatasa', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(106 AS Decimal(5, 0)), N'Auditoría de sistemas de APPCC/HACCP', N'Establecer las condiciones y requisitos que deben valorarse en una auditoría para evaluar si un establecimiento dispone de un sistema de autocontrol  correctamente planificado, implantado y ejecutado.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
GO
INSERT [SYSPRO].[TSCIJPR1] ([TPR1_COD_TIPO], [TPR1_DES_TIPO], [TPR1_TEX_TIPO], [TPR1_DES_TIPO_E], [TPR1_TEX_TIPO_E], [TPR1_FEC_BAJA]) VALUES (CAST(107 AS Decimal(5, 0)), N'Complementos alimenticios', N'Establecer las condiciones y requisitos que de forma específica deben cumplir los establecimientos dedicados a la actividad de elaboración, envasado y comercialización de complementos alimenticios así como las condiciones y requisitos de los productos que se producen o comercializan en dichos establecimientos.', N'DESCRIPCION_EUSKERA', N'TEXTO_EUSKERA', CAST(N'0001-01-01' AS Date))
